import { BoardEntity } from '../../../board-entity';
import { CardIds } from '../../../services/card-ids';
import { OnOtherSpawnInput } from '../../../simulation/add-minion-to-board';
import { modifyStats } from '../../../simulation/stats';
import { AfterOtherSpawnedCard, DefaultChargesCard } from '../../card.interface';

export const StalwartKodo: AfterOtherSpawnedCard & DefaultChargesCard = {
	cardIds: [CardIds.StalwartKodo_BG34_322, CardIds.StalwartKodo_BG34_322_G],
	defaultCharges: (entity: BoardEntity) => 3,
	afterOtherSpawned: (minion: BoardEntity, input: OnOtherSpawnInput) => {
		const mult = minion.cardId === CardIds.StalwartKodo_BG34_322_G ? 2 : 1;
		if (minion.abiityChargesLeft > 0) {
			minion.abiityChargesLeft--;
			modifyStats(
				input.spawned,
				minion,
				minion.maxAttack * mult,
				minion.maxHealth * mult,
				input.board,
				input.hero,
				input.gameState,
			);
			return;
		}
	},
};
